// Platform configuration for the icon row
export const allSocialPlatforms = [
  { key: 'youtube' as const, label: 'YouTube', Icon: YouTubeIcon, color: '#FF0000' },
  { key: 'instagram' as const, label: 'Instagram', Icon: InstagramIcon, color: '#E4405F' },
  { key: 'tiktok' as const, label: 'TikTok', Icon: TikTokIcon, color: '#000000' },
  { key: 'twitter' as const, label: 'Twitter/X', Icon: TwitterIcon, color: '#000000' },
  { key: 'facebook' as const, label: 'Facebook', Icon: FacebookIcon, color: '#1877F2' },
  { key: 'linkedin' as const, label: 'LinkedIn', Icon: LinkedInIcon, color: '#0A66C2' },
  { key: 'twitch' as const, label: 'Twitch', Icon: TwitchIcon, color: '#9146FF' },
  { key: 'website' as const, label: 'Website', Icon: WebsiteIcon, color: '#3B82F6' },
  { key: 'email' as const, label: 'Email', Icon: EmailIcon, color: '#F97316' },
]

// Social links data structure
export interface SocialLinksData {
  youtube?: string | null
  instagram?: string | null
  tiktok?: string | null
  twitter?: string | null
  facebook?: string | null
  linkedin?: string | null
  twitch?: string | null
  website?: string | null
  email?: string | null
}

/**
 * Always shows all platform icons in a row.
 * Active (has URL) icons are colored and clickable.
 * Inactive icons are light gray and non-interactive.
 */
export function PlatformTags({ links }: { links: SocialLinksData }) {
  const INACTIVE_COLOR = "#e5e7eb" // gray-200

  return (
    <div className="flex items-center gap-1">
      {allSocialPlatforms.map(({ key, label, Icon, color }) => {
        const url = links[key]

        if (url) {
          // Email uses mailto: link
          const href = key === 'email' ? `mailto:${url}` : url
          // Active: colored icon, clickable link
          return (
            <a
              key={key}
              href={href}
              target={key !== 'email' ? '_blank' : undefined}
              rel={key !== 'email' ? 'noopener noreferrer' : undefined}
              className="p-1 rounded-md transition-colors hover:bg-gray-100"
              title={`${label}: ${url}`}
            >
              <Icon color={color} />
            </a>
          )
        }

        // Inactive: gray icon, no interaction
        return (
          <span
            key={key}
            className="p-1 rounded-md transition-colors opacity-40"
            title={label}
          >
            <Icon color={INACTIVE_COLOR} />
          </span>
        )
      })}
    </div>
  )
}

// Legacy export for backward compatibility (used in list view)
const platformColors: Record<string, string> = {
  Instagram: "#E4405F",
  TikTok: "#000000",
  YouTube: "#FF0000",
}

export function PlatformBadge({ platforms }: { platforms: string[] | string | null }) {
  const platformList = Array.isArray(platforms)
    ? platforms
    : platforms
      ? [platforms]
      : []

  const hasPlatform = (key: string) => platformList.includes(key)

  const legacyPlatforms = [
    { key: "Instagram", Icon: InstagramIcon },
    { key: "TikTok", Icon: TikTokIcon },
    { key: "YouTube", Icon: YouTubeIcon },
  ]

  return (
    <div className="flex items-center gap-0.5">
      {legacyPlatforms.map(({ key, Icon }) => {
        const active = hasPlatform(key)
        const color = active ? platformColors[key] : "#e5e7eb"
        return (
          <span
            key={key}
            className={cn(
              "p-1 rounded-md transition-colors",
              active && "hover:bg-gray-100"
            )}
            title={key}
          >
            <Icon color={color} />
          </span>
        )
      })}
    </div>
  )
}
